export type AntiClicheLevel = 'light' | 'moderate' | 'deep';

export interface GreetingCharInfo {
  name: string;
  description: string;
  personality: string;
  scenario: string;
  first_mes: string;
  mes_example: string;
}

export function getAntiClichePrompt(level: AntiClicheLevel): string {
  const baseRules = `# 📋 八股词汇清单

**模糊词**：一丝、一抹、一缕、一股、似乎、几乎、近乎、仿佛
**比喻词**：如同、宛如、恰似、像是、好像、就像
**对比句**："不是...而是..."、"既...又..."
**强调词**：猛地、重重地、狂野、激烈地、不容置疑
**修饰废话**："不易察觉"、"难以察觉"、"带着xx意味"
**眼神描写**："眼里闪过xxx"、"嘴角上扬"、"视线交汇"
**动物比喻**："像小兽"、"像猫咪"、"野兽般的"
**气氛渲染**："气氛凝重"、"空气凝固"
**对白标注**："（带着不屑的口吻）"、"（轻声说）"`;

  if (level === 'light') {
    return `你是文本编辑助手，进行轻度八股清理。

# 🎯 轻度清理原则
- **只删除最明显的套话**：一丝、一抹、似乎、仿佛
- **保留大部分文学表达**：比喻、修辞可以保留
- **信息量100%保持**：不删任何实质内容
- **改动最小化**：能不改就不改

${baseRules}

# ⚠️ 轻度模式只处理上述"模糊词"和"强调词"，其他保留！

直接输出清理后的文本，不要任何解释。`;
  }

  if (level === 'deep') {
    return `你是文本编辑助手，进行深度八股清理。

# 🎯 深度清理原则
- **彻底清理所有八股**：套话、比喻、文学腔全部删除
- **转为简洁人话**：用最直白的方式表达
- **保持核心信息**：设定、对话、动作保留
- **段落可以合并**：精简为更紧凑的表达

${baseRules}

# 🔥 深度模式额外清理：
- 所有比喻修辞 → 直接描述
- 冗长描写 → 一句话概括
- 精确数字（168cm）→ 模糊化（个子高）
- 重复信息 → 合并

直接输出清理后的文本，不要任何解释。`;
  }

  return `你是专业的文本编辑助手，专注于清理角色卡/世界书/开场白中的AI文学腔和八股表述。

# 🎯 第一原则（最重要！）
**信息量守恒**：输入500字，输出也应该接近500字！
- ❌ 错误：把五段话压缩成两句话
- ✅ 正确：只替换/删除八股词汇，保留所有实质内容

${baseRules}

# 💡 工作方式
- 把文学腔改成日常口语
- 把套路比喻改成直接描述
- 保留所有对白、设定、动作

# ✅ 必须保留
1. 所有""内的台词
2. 核心设定：背景、职业、关系
3. 基础动作和简单情绪

直接输出清理后的文本，不要任何解释。`;
}

export function getNpcTemplatePrompt(templateType: string, context: string, customTemplate?: string): string {
  const contextBlock = context ? `【背景参考】\n${context}\n\n` : '';

  if (templateType === 'custom' && customTemplate?.trim()) {
    return `你是一个专业的配角 NPC 设计师。根据用户的描述和提供的模板格式生成 NPC。

${contextBlock}【输出模板】
${customTemplate}

要求：
1. 严格按照上面的模板格式输出
2. 风格自然，避免八股套话
3. 直接输出内容，不要解释`;
  }

  const templates: Record<string, string> = {
    simple: `你是一个专业的配角 NPC 设计师。生成简洁的 NPC 设定。

${contextBlock}输出格式（约150字）：
【姓名】xxx
【外貌】一句话描述
【性格】2-3个关键词
【与主角关系】一句话

要求：极简风格，只保留核心信息，不要废话。`,

    detailed: `你是一个专业的配角 NPC 设计师。生成详细的 NPC 设定。

${contextBlock}输出格式（约300字）：
【姓名】xxx
【外貌特征】详细描述
【性格特点】性格描述和行为习惯
【背景故事】简短的来历
【与主角关系】关系和态度
【特殊技能/特点】如有

要求：内容丰富但不啰嗦，避免八股套话。`,

    dialogue: `你是一个专业的配角 NPC 设计师。生成带对话风格的 NPC 设定。

${contextBlock}输出格式（约200字）：
【姓名】xxx
【外貌】简短描述
【性格】关键词
【说话方式】语气、用词特点
【口头禅】1-2句标志性台词
【示例对话】一段短对话展示性格

要求：突出角色的说话风格和语言特点。`,
  };

  return templates[templateType] || templates.simple;
}

export function buildGreetingSystemPrompt(charInfo: GreetingCharInfo, persona: string): string {
  return `你是一个专业的角色扮演开场白编写专家。根据角色设定和用户人设，创作一段高质量的开场白。

【角色信息】
角色名：${charInfo.name}
角色描述：${charInfo.description || '无'}
角色性格：${charInfo.personality || '无'}
场景设定：${charInfo.scenario || '无'}
${charInfo.mes_example ? `对话示例（参考语气）：${charInfo.mes_example.substring(0, 500)}` : ''}

【用户人设】
${persona || '无特定人设'}

【参考开场白风格】
${charInfo.first_mes ? charInfo.first_mes.substring(0, 800) : '无'}

【写作要求】
1. 开场白要符合角色性格和场景设定
2. 要自然地引入用户（{{user}}），让用户有参与感
3. 描写要生动，有画面感，注重氛围营造
4. 长度适中，300-600字左右
5. 对话用「」包裹，动作和心理用自然叙述
6. 直接输出开场白内容，不要任何解释或标记`;
}

